import{_ as a,o as s,c as t,ae as o}from"./chunks/framework.CY_fclge.js";const h=JSON.parse('{"title":"Implementación de el Fractalismo de Privacidad.","description":"","frontmatter":{},"headers":[],"relativePath":"es/Fractalismo.md","filePath":"es/Fractalismo.md"}'),i={name:"es/Fractalismo.md"};function n(l,e,d,c,r,p){return s(),t("div",null,[...e[0]||(e[0]=[o(`<h1 id="implementacion-de-el-fractalismo-de-privacidad" tabindex="-1">Implementación de el Fractalismo de Privacidad. <a class="header-anchor" href="#implementacion-de-el-fractalismo-de-privacidad" aria-label="Permalink to &quot;Implementación de el Fractalismo de Privacidad.&quot;">​</a></h1><p><em>No usamos una “base de datos con cifrado”; tratamos el espacio lógico como una estructura derivable cuya visibilidad solo se resuelve ante la cadena correcta de secretos.</em></p><p><strong>Proxies como Superficie Infinita:</strong> Al usar <code>me.cualquier.cosa</code>, permites que el usuario declare realidad en lugar de llenar un formulario predefinido. Es el paso del &quot;Schema-First&quot; al &quot;Existence-First&quot;.</p><p><strong>El Secreto como Operador de Fase:</strong> Cuando haces <code>me.wallet.secret(&quot;ABC&quot;)</code>, no estás moviendo los datos a otro lugar. Estás cambiando la fase de visibilidad de esa rama. Si no tienes &quot;ABC&quot;, esa rama es indistinguible del vacío (0), cumpliendo tu <strong>Nivel 0:</strong> <code>presencia/ausencia.</code> Invarianza y Portabilidad: Al ser zero dependencies y generar un deterministic structure, el <strong>.me</strong> de un usuario es una partícula lógica que puede viajar de Node al Browser sin perder su ontología.</p><p><code>me.wallet.balance(500).secret(&quot;XYZ&quot;);</code></p><p>Esto implica que el Estado del objeto <strong>.me</strong> cambia su comportamiento interno basándose en la profundidad del árbol. Es una estructura de datos que sabe en qué dimensión está operando.</p><h3 id="estas-son-las-jugadas-que-ya-puedes-hacer" tabindex="-1"><strong>Estas son las jugadas que ya puedes hacer:</strong> <a class="header-anchor" href="#estas-son-las-jugadas-que-ya-puedes-hacer" aria-label="Permalink to &quot;**Estas son las jugadas que ya puedes hacer:**&quot;">​</a></h3><p><strong>Aritmética Directa:</strong><code>me.wallet[&quot;=&quot;](&quot;neto&quot;, &quot;ingresos - gastos&quot;)</code> El sistema busca &quot;ingresos&quot; y &quot;gastos&quot; en la misma rama o en el índice y los resta.</p><p><strong>Aritmética Cruzada (Wormholes):</strong><code>me.wallet[&quot;=&quot;](&quot;balance&quot;, &quot;__ptr.global.base + ingresos&quot;)</code> Gracias a tu lógica de __ptr., puedes traer un valor de otra galaxia (otra rama) y sumarlo a la tuya.</p><p><strong>Cómputo en la Raíz (Thunks):</strong><code>me[&quot;=&quot;](() =&gt; 2 + 2)</code> Esto no guarda nada, solo usa el cerebro de ME para darte un resultado rápido.</p><h3 id="la-gramatica-de-la-proyeccion" tabindex="-1">La Gramática de la &quot;Proyección&quot; (?) <a class="header-anchor" href="#la-gramatica-de-la-proyeccion" aria-label="Permalink to &quot;La Gramática de la &quot;Proyección&quot; (?)&quot;">​</a></h3><p>Este es tu operador de Consulta (Query). Es como preguntarle al universo qué hay ahí afuera: <strong>Recolección (Collector):</strong><code>me[&quot;?&quot;]([&quot;perfil.nombre&quot;, &quot;wallet.neto&quot;])</code> Te devuelve un array [&quot;Abella&quot;, 500]. Es una foto de varios puntos del fractal a la vez.</p><p><strong>Transformación:</strong><code>me[&quot;?&quot;]([&quot;ingresos&quot;, &quot;gastos&quot;], (a, b) =&gt; a &gt; b ? &quot;Ganancia&quot; : &quot;Pérdida&quot;)</code> No solo lee, sino que decide qué decirte basado en los datos.</p><h3 id="la-gramatica-de-la-invisibilidad-y" tabindex="-1">La Gramática de la &quot;Invisibilidad&quot; (_ y ~) <a class="header-anchor" href="#la-gramatica-de-la-invisibilidad-y" aria-label="Permalink to &quot;La Gramática de la &quot;Invisibilidad&quot; (_ y ~)&quot;">​</a></h3><p>Estos no son solo para guardar, son operadores de estado.</p><p><strong>Enmascaramiento:</strong><code>me.secreto[&quot;_&quot;](&quot;mi-llave&quot;)</code> Cambia la &quot;física&quot; de todo lo que cuelga de ahí. Los datos dejan de ser legibles para el índice público.</p><p><strong>Pared de Humo (Noise):</strong><code>me.capa[&quot;~&quot;](&quot;ruido-extra&quot;)</code> Corta la herencia. Es un &quot;reset&quot; de seguridad.</p><h3 id="fisica-de-la-observacion-stm" tabindex="-1"><strong>Física de la Observación. STM</strong> - <a class="header-anchor" href="#fisica-de-la-observacion-stm" aria-label="Permalink to &quot;**Física de la Observación. STM** -&quot;">​</a></h3><p>El memories es el registro genético de cómo llegaste ahí. Si borras el index, puedes reconstruir tu universo entero simplemente &quot;volviendo a pensar&quot; los pensamientos de la STM.</p><p><strong>A8 (Integridad de Cadena):</strong> Al incluir prevHash en el hashInput, has creado un vínculo criptográfico. Si alguien cambia el pasado, el presente &quot;se desintegra&quot; porque el hash ya no coincide. Es el fin de la mutabilidad silenciosa. <strong>A9 (Determinismo Total):</strong> Tu lógica de .sort((a, b) =&gt; ...) con triple fallback (timestamp -&gt; hash -&gt; index) asegura que no existe la ambigüedad. Si dos eventos ocurren en el mismo milisegundo, el hash (que es único) rompe el empate. Esto es arquitectura de sistemas distribuidos nivel &quot;Senior Staff&quot;.</p><h1 id="secretos-y-ruido" tabindex="-1">Secretos y Ruido <a class="header-anchor" href="#secretos-y-ruido" aria-label="Permalink to &quot;Secretos y Ruido&quot;">​</a></h1><p><code>[&quot;_&quot;]</code> es privacidad estructural — define quién puede ver qué. <code>[&quot;~&quot;]</code> es discontinuidad criptográfica — redefine de dónde viene la cadena de derivación. Son ortogonales. Puedes tener uno sin el otro.</p><p>El caso concreto lo clavó:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A + B  →  nota        (sin ~, hereda toda la genealogía)</span></span>
<span class="line"><span>N + B  →  nota        (con ~, A quedó amputado del árbol de derivación)</span></span></code></pre></div><p>Eso no es solo &quot;más privacidad&quot; — es un reset de linaje. La nota sigue siendo secreta con B, pero ya no hay forma de demostrar que alguna vez estuvo relacionada con A. Eso tiene implicaciones reales: dos ramas con el mismo <code>[&quot;_&quot;]</code> ancestral pero con <code>[&quot;~&quot;]</code> entre ellas son criptográficamente independientes aunque compartan el árbol lógico.</p><p>El riesgo de colisión es efectivamente cero en la práctica.</p><p>El noise no es un número pequeño. Si <code>[&quot;~&quot;](&quot;N&quot;)</code> toma <code>N</code> y lo pasa por <code>hash(&quot;noise::N&quot;)</code> antes de sembrar la cadena, estás trabajando en un espacio de 2^256. La probabilidad de que dos noises distintos produzcan el mismo punto de arranque es astronómicamente baja — del orden de encontrar dos archivos distintos con el mismo SHA-256.</p><p>La derivación efectiva no es solo el noise — es <code>noise + path</code>. Entonces aunque <code>N</code> sea el mismo:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>trabajo.leaf   →  hash(N + &quot;trabajo.leaf&quot;)</span></span>
<span class="line"><span>personal.leaf  →  hash(N + &quot;personal.leaf&quot;)</span></span></code></pre></div><p>Los paths son distintos, entonces las claves finales son distintas. No hay conflicto de datos, no se mezcla nada.</p><p>Lo único que comparten es el origen abstracto — como dos ríos que nacen del mismo manantial pero fluyen por cañones distintos. El agua de uno nunca toca al otro.</p><hr><h2 id="me-kernel" tabindex="-1">.me Kernel <a class="header-anchor" href="#me-kernel" aria-label="Permalink to &quot;.me Kernel&quot;">​</a></h2><p>No hay aviso de doble uso de noise. Así que hoy es responsabilidad del usuario.</p><p><strong>Sí hay una sutileza importante:</strong> reutilizar el mismo <code>noise</code> en dos ramas no implica que los blobs finales colisionen. La derivación v3 mezcla no solo el lineage, sino también <code>scopePath</code>, <code>anchorPath</code> y <code>pathContext</code> en <code>collectSecretChainV3(...)</code> de <code>src/secret-context.ts</code> y <code>deriveBlobV3Keys(...)</code> de <code>src/crypto.ts</code>. O sea:</p><ul><li>mismo <code>noise</code></li><li>incluso mismo secret local</li><li>ramas distintas</li></ul><p>pueden dar el mismo <code>computeEffectiveSecret(...)</code> lógico, pero aun así producir blobs distintos por el path. Eso sí: si alguien ve un snapshot completo, <code>localNoises</code> sí sale exportado en claro en <code>exportSnapshot(...)</code> de <code>src/core-snapshot.ts</code>, así que la reutilización puede filtrar “estas dos ramas comparten el mismo seed semántico”.</p><p><strong>Sobre el caso que cierra el modelo mental:</strong></p><p>No sale <code>effective = N</code>. Sale <code>effective = N + B</code>.</p><p>Porque el código corta los secretos por arriba del noise boundary, pero conserva el secreto del mismo nodo cuando el secreto cae dentro del boundary activo, como se ve en <code>computeEffectiveSecret(...)</code> de <code>src/secret-context.ts</code>.</p><p>El árbol “<strong>según la lógica de derivación del código</strong>” queda así:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CASO:</span></span>
<span class="line"><span>root[&quot;_&quot;](&quot;A&quot;)</span></span>
<span class="line"><span>root.child[&quot;_&quot;](&quot;B&quot;)</span></span>
<span class="line"><span>root.child[&quot;~&quot;](&quot;N&quot;)</span></span>
<span class="line"><span>root.child.leaf(&quot;x&quot;)</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span>root                   scope=root(A)         effective=A</span></span>
<span class="line"><span>  child [_ B]         scope=child(B)        effective=A+B</span></span>
<span class="line"><span>                       cambia el dueño estructural aquí</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  child [~ N]         scope=child(B)        effective=N+B</span></span>
<span class="line"><span>                       corta A</span></span>
<span class="line"><span>                       conserva B porque B vive en el mismo noise boundary</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    leaf=&quot;x&quot;          scope=child(B)        effective=N+B</span></span>
<span class="line"><span>                       hereda N+B</span></span>
<span class="line"><span>                       no hereda A</span></span></code></pre></div><p>Y el caso 4, al lado, para comparar:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CASO 4:</span></span>
<span class="line"><span>wallet[&quot;_&quot;](&quot;A&quot;)</span></span>
<span class="line"><span>wallet.hidden.notes(&quot;alpha-note&quot;)</span></span>
<span class="line"><span>wallet[&quot;~&quot;](&quot;N&quot;)</span></span>
<span class="line"><span>wallet[&quot;_&quot;](&quot;B&quot;)</span></span>
<span class="line"><span>wallet.hidden.seed(&quot;beta-seed&quot;)</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span>wallet                 scope=wallet(A)       effective=A</span></span>
<span class="line"><span>  hidden.notes         scope=wallet(A)       effective=A</span></span>
<span class="line"><span>                       escrito en la generación vieja</span></span>
<span class="line"><span></span></span>
<span class="line"><span>wallet [~ N] [_ B]     scope=wallet(B)       effective=N+B</span></span>
<span class="line"><span>                       mismo nodo, nuevo lineage efectivo</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  hidden.seed          scope=wallet(B)       effective=N+B</span></span>
<span class="line"><span>                       escrito en la generación nueva</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  hidden.notes         old blob @ A</span></span>
<span class="line"><span>                       lectura actual intenta N+B</span></span>
<span class="line"><span>                       =&gt; queda fuera / fail closed</span></span></code></pre></div><p>La diferencia conceptual entre ambos es:</p><ul><li><code>child</code> ya era el dueño estructural por <code>[&quot;_&quot;](&quot;B&quot;)</code>; luego <code>~</code> no le quita ese ownership. Solo le cambia la cadena efectiva de <code>A+B</code> a <code>N+B</code>.</li><li>En el caso 4, pasa algo parecido en el mismo nodo <code>wallet</code>, pero además ves muy claro el corte temporal entre “datos escritos antes del reset” y “datos escritos después”.</li></ul><p>Sobre el orden <code>_</code> y <code>~</code> en el mismo nodo: el estado final no cambia.</p><p>Estas dos secuencias terminan con el mismo mapa final de secretos/noises y el mismo lineage efectivo:</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">root[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;_&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">](</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;A&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">root.child[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;_&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">](</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;B&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">root.child[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;~&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">](</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;N&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">root[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;_&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">](</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;A&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">root.child[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;~&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">](</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;N&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">root.child[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;_&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">](</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;B&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p>Eso es porque el cálculo final lee los mapas actuales <code>localSecrets</code> y <code>localNoises</code>, no el orden histórico de memorias: <code>registerStealthScope(...)</code> y el manejo del operador <code>~</code> en <code>src/core-write.ts</code>, junto con <code>computeEffectiveSecret(...)</code> en <code>src/secret-context.ts</code>.</p><p>Lo que sí cambia con el orden es qué escrituras históricas quedaron cifradas con el linaje viejo y cuáles con el nuevo.</p><h4 id="la-regla-mental-se-actualiza-a" tabindex="-1">La regla mental se actualiza a: <a class="header-anchor" href="#la-regla-mental-se-actualiza-a" aria-label="Permalink to &quot;La regla mental se actualiza a:&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~ corta todo lo que está SOBRE ese nodo</span></span>
<span class="line"><span>~ conserva el _ que está EN ese mismo nodo</span></span>
<span class="line"><span>~ no toca nada de abajo</span></span></code></pre></div><table tabindex="0"><thead><tr><th style="text-align:left;">Caso</th><th style="text-align:left;">Scope estructural</th><th style="text-align:left;">Effective Lineage</th><th style="text-align:left;">Read owner</th><th style="text-align:left;">Read guest</th></tr></thead><tbody><tr><td style="text-align:left;">~ arriba, _ abajo</td><td style="text-align:left;">manda el _ de abajo</td><td style="text-align:left;">noise + secret_abajo</td><td style="text-align:left;">sí</td><td style="text-align:left;">no</td></tr><tr><td style="text-align:left;">_ arriba, ~ abajo</td><td style="text-align:left;">manda el _ de arriba</td><td style="text-align:left;">noise + cualquier _ en el boundary o debajo</td><td style="text-align:left;">sí</td><td style="text-align:left;">no</td></tr><tr><td style="text-align:left;">_ y ~ mismo nodo</td><td style="text-align:left;">manda ese mismo nodo</td><td style="text-align:left;">noise + secret_de_ese_mismo_nodo</td><td style="text-align:left;">sí</td><td style="text-align:left;">no</td></tr><tr><td style="text-align:left;">~ sin _</td><td style="text-align:left;">no hay scope secreto</td><td style="text-align:left;">puede calcular noise, pero no hay contexto secreto válido</td><td style="text-align:left;">write inválido / edge case</td><td style="text-align:left;">no aplica</td></tr></tbody></table><ol><li><h4 id="operators" tabindex="-1">Operators: <a class="header-anchor" href="#operators" aria-label="Permalink to &quot;Operators:&quot;">​</a></h4><p><code>[&quot;~&quot;] sin [&quot;_&quot;] ancestro es write inválido. Define un scope secreto primero.</code></p></li><li><h4 id="security" tabindex="-1">Security: <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security:&quot;">​</a></h4><p><code>[&quot;~&quot;] reutilizado en ramas distintas comparte linaje criptográfico. Usa noises únicos si necesitas aislamiento total.</code></p><p>Sí puedes poner <code>[&quot;~&quot;]</code> después de paths públicos. Lo que no puedes es escribir data secreta si no hay ningún <code>[&quot;_&quot;]</code> ancestro.</p><p><code>[&quot;~&quot;]</code> no crea privacidad. Solo corta la herencia criptográfica. <code>[&quot;_&quot;]</code> crea el cuarto secreto.</p><h3 id="la-regla-exacta" tabindex="-1">La regla exacta: <a class="header-anchor" href="#la-regla-exacta" aria-label="Permalink to &quot;La regla exacta:&quot;">​</a></h3><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Caso 1: VÁLIDO ✅me.public[&quot;_&quot;](&quot;A&quot;);</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     // ← crea scope secreto en publicme.public.child[&quot;~&quot;](&quot;N&quot;);</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> // ← corta A, resembra en Nme.public.child.secret(&quot;x&quot;);</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> // ← escribe bajo scope=public(A), effective=N</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Caso 2: INVÁLIDO ❌  me.public[&quot;~&quot;](&quot;N&quot;);</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     // ← intenta cortar herencia... pero no hay herenciame.public.secret(&quot;x&quot;);</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   // ← Error: No secret context active</span></span></code></pre></div><h3 id="por-que" tabindex="-1">Por qué: <a class="header-anchor" href="#por-que" aria-label="Permalink to &quot;Por qué:&quot;">​</a></h3><p><code>[&quot;_&quot;]</code> hace 2 cosas:</p><ol><li>Marca el nodo como <code>stealth</code> = invisible en lecturas públicas</li><li>Registra <code>secret</code> en <code>localSecrets[path]</code></li></ol><p><code>[&quot;~&quot;]</code> hace 1 cosa:</p><ol><li>Registra <code>noise</code> en <code>localNoises[path]</code> y dice “desde aquí abajo, ignora secrets de arriba”</li></ol><p>Si escribes <code>me.node(&quot;valor&quot;)</code> y <code>node</code> no vive bajo ningún <code>[&quot;_&quot;]</code>, el kernel no sabe dónde guardar el secreto. Por eso tira <code>No secret context active</code>.</p><h3 id="como-pensar-sin" tabindex="-1">Cómo pensar <code>~</code> sin <code>_</code>: <a class="header-anchor" href="#como-pensar-sin" aria-label="Permalink to &quot;Cómo pensar \`~\` sin \`_\`:&quot;">​</a></h3><p>Es como decir “a partir de aquí, olvida la historia familiar”... pero si nunca hubo familia = <code>[&quot;_&quot;]</code>, no hay nada que olvidar. Es un no-op que confunde.</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">me.root[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;~&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">](</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;N&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);        </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// noise registrado, pero sin efectome.root.child(&quot;x&quot;);</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       // x es público. N no se usó para nadame.root.child(&quot;_&quot;)</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        // Error: no hay scope donde guardar</span></span></code></pre></div><h3 id="como-usarlo-bien" tabindex="-1">Cómo usarlo bien: <a class="header-anchor" href="#como-usarlo-bien" aria-label="Permalink to &quot;Cómo usarlo bien:&quot;">​</a></h3><p><code>[&quot;~&quot;]</code> solo tiene sentido en 3 situaciones:</p><ol><li>Entre dos <code>[&quot;_&quot;]</code> para cortar herencia:</li></ol><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">me.wallet[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;_&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">](</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;A&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// dueño viejome.wallet.box[&quot;~&quot;](&quot;N&quot;);</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // caja nueva, olvida Ame.wallet.box[&quot;_&quot;](&quot;B&quot;);</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // dueño nuevome.wallet.box.note(&quot;x&quot;);</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // effective = N+B, no A</span></span></code></pre></div><ol start="2"><li>Debajo de un <code>[&quot;_&quot;]</code> para resetear ramas:</li></ol><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">me.app[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;_&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">](</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;root-key&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);me.app.user1[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;~&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">](</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;N1&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// user1 no hereda root-keyme.app.user2[&quot;~&quot;](&quot;N2&quot;);</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // user2 tampoco, y N1 ≠ N2</span></span></code></pre></div><ol start="3"><li>En el mismo nodo que <code>[&quot;_&quot;]</code> para rekey:</li></ol><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">me.vault[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;_&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">](</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;old&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);me.vault[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;~&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">](</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;N&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// corta oldme.vault[&quot;_&quot;](&quot;new&quot;);</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     // nuevo dueñome.vault.doc(&quot;x&quot;);</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        // effective = N+new</span></span></code></pre></div><h3 id="respuesta-directa" tabindex="-1">Respuesta directa: <a class="header-anchor" href="#respuesta-directa" aria-label="Permalink to &quot;Respuesta directa:&quot;">​</a></h3><p>¿Puedes poner <code>~</code> después de paths públicos? <strong>Sí.</strong> ¿Puedes escribir secretos ahí? No, hasta que algún ancestro tenga <code>[&quot;_&quot;]</code>.</p><p>Si quieres que <code>me.public.child</code> sea secreto pero con linaje cortado, haz:</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">me.public[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;_&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">](</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;key&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// abre el cuarto secretome.public.child[&quot;~&quot;](&quot;N&quot;);</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // corta key para child y descendientes  me.public.child.data(&quot;x&quot;);</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // x vive bajo scope=public, effective=N</span></span></code></pre></div><p><strong>¿Queda claro?</strong> <code>~</code> es tijeras. <code>_</code> es la caja fuerte. Necesitas la caja antes de usar tijeras.</p></li></ol>`,56)])])}const q=a(i,[["render",n]]);export{h as __pageData,q as default};
